/* particles.js v2.0.0 - Fixed deepExtend Error */
window.particlesJS = function(divId, config) {
  var canvasContainer = document.getElementById(divId);
  if (!canvasContainer) return;
  
  var oldCanvas = canvasContainer.getElementsByClassName("particles-js-canvas-el");
  while(oldCanvas.length > 0) { canvasContainer.removeChild(oldCanvas[0]); }

  var canvas = document.createElement("canvas");
  canvas.className = "particles-js-canvas-el";
  canvas.style.width = "100%";
  canvas.style.height = "100%";
  canvasContainer.appendChild(canvas);

  var ctx = canvas.getContext("2d");
  var particlesArray = [];
  
  function resizeCanvas() {
    canvas.width = canvasContainer.offsetWidth;
    canvas.height = canvasContainer.offsetHeight;
  }
  resizeCanvas();
  window.addEventListener("resize", resizeCanvas);

  function Particle() {
    this.x = Math.random() * canvas.width;
    this.y = Math.random() * canvas.height;
    this.vx = (Math.random() - 0.5) * 0.1; // Tốc độ gió thổi nhẹ ngang
    this.vy = (Math.random() - 0.5) * 0.4;
    this.radius = Math.random() * 1.8;     // Độ lớn hạt sao nhỏ xinh
    this.opacity = Math.random();
    this.fadeSpeed = Math.random() * 0.01 + 0.005;
  }

  Particle.prototype.draw = function() {
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
    ctx.fillStyle = "rgba(255, 255, 255, " + this.opacity + ")";
    ctx.fill();
  };

  Particle.prototype.update = function() {
    this.x += this.vx;
    this.y += this.vy;
    
    // Hiệu ứng làm mờ và lấp lánh tự động
    this.opacity -= this.fadeSpeed;
    if (this.opacity <= 0 || this.opacity >= 1) {
      this.fadeSpeed = -this.fadeSpeed;
    }

    if (this.x < 0 || this.x > canvas.width) this.vx = -this.vx;
    if (this.y < 0 || this.y > canvas.height) this.vy = -this.vy;
  };

  for (var i = 0; i < 50; i++) { particlesArray.push(new Particle()); }

  function animate() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (var i = 0; i < particlesArray.length; i++) {
      particlesArray[i].update();
      particlesArray[i].draw();
    }
    requestAnimationFrame(animate);
  }
  animate();
};
